const item = $input.first();
const data = item.json;

const tweets = data.tweets || [];

if (tweets.length === 0) {
  return [{ json: { signal: "NO_TRADE", reason: "Nenhum tweet retornado pela API" } }];
}

return tweets.map(function(tweet) {
  return {
    json: {
      id: tweet.id || "",
      text: tweet.text || "",
      author: (tweet.author && tweet.author.userName) || "",
      author_followers: (tweet.author && tweet.author.followers) || 0,
      createdAt: tweet.createdAt || "",
      retweetCount: tweet.retweetCount || 0,
      likeCount: tweet.likeCount || 0,
      viewCount: tweet.viewCount || 0,
      url: tweet.url || "",
      isReply: tweet.isReply || false,
      author_verified: (tweet.author && (tweet.author.isBlueVerified || tweet.author.isVerified)) || false
    }
  };
});

const item = $input.first();
const tweet = item.json;

if (tweet.signal === "NO_TRADE") { return [item]; }

// ── Deduplicação: evitar reprocessar o mesmo tweet ───────────────────────
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedTweetIds) {
  staticData.processedTweetIds = {};
}

// Limpar entradas com mais de 2 horas (TTL)
const TWO_HOURS = 2 * 60 * 60 * 1000;
const now = Date.now();
for (const id of Object.keys(staticData.processedTweetIds)) {
  if (now - staticData.processedTweetIds[id] > TWO_HOURS) {
    delete staticData.processedTweetIds[id];
  }
}

const tweetId = tweet.id || "";
if (tweetId && staticData.processedTweetIds[tweetId]) {
  return [{ json: { signal: "NO_TRADE", reason: "Tweet já processado (deduplicação): " + tweetId } }];
}

// Marcar como processado antes de continuar (otimistic)
if (tweetId) {
  staticData.processedTweetIds[tweetId] = now;
}

// ── Filtro de recência ────────────────────────────────────────────────────
const createdAt = tweet.createdAt || "";
if (createdAt) {
  const tweetDate = new Date(createdAt);
  const minutesAgo = (now - tweetDate.getTime()) / 60000;
  if (minutesAgo > 35) {
    return [{ json: { signal: "NO_TRADE", reason: "Tweet mais antigo que 35 minutos (" + Math.round(minutesAgo) + "min)" } }];
  }
}

return [{
  json: {
    news_text: tweet.text || "",
    tweet_id: tweetId,
    tweet_url: tweet.url || "",
    author: tweet.author || "",
    author_followers: tweet.author_followers || 0,
    author_verified: tweet.author_verified || false,
    timestamp: new Date().toISOString()
  }
}];

const item = $input.first();
const data = item.json;

function sanitize(text) {
  return (text || "")
    .replace(/https?:\/\/\S+/g, "")
    .replace(/\*/g, "")
    .replace(/[\uD800-\uDFFF]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

const originalText = data.news_text || "";
const tweetText = sanitize(originalText);
const author = data.author || "";
const followers = data.author_followers || 0;

const isVerified = data.author_verified || false;

// ── Credibility score ─────────────────────────────────────────────────────
let credibilityScore = 0;
if (followers >= 1000000) credibilityScore += 50;
else if (followers >= 100000) credibilityScore += 30;
else if (followers >= 10000) credibilityScore += 15;
else if (followers >= 1000) credibilityScore += 5;
if (isVerified) credibilityScore += 20;

// ── Geopolitical pre-filter: accounts < 1k followers are unreliable ────────
const GEOPOLITICAL_PATTERN = /\b(war|attacked?|missile|nuclear|invasion|invaded?|military|troops|sanctions?|ceasefire|coup|conflict|elections?|nato|treaty|bombing?|airstrike|explosion|assassination|hostage|forces|army|navy|president|prime\s+minister)\b/i;
const isGeopolitical = GEOPOLITICAL_PATTERN.test(originalText);

if (isGeopolitical && followers < 1000) {
  return [{ json: { ...data, ai_prompt: "NO_TRADE", pre_no_trade: true, pre_no_trade_reason: `Geopolitical news from low-credibility account (${followers} followers, verified: ${isVerified})`, credibility_score: credibilityScore } }];
}


// ── Category filter: check user preferences ─────────────────────────────
const staticData = $getWorkflowStaticData('global');
const userFilters = staticData.userFilters || { geopolitica: true, crypto: true, economia: true, esportes: true };

const CATEGORIES = {
  geopolitica: /\b(war|attack(ed|s)?|missile|nuclear|invasion|invade[sd]?|military|troops|sanctions?|ceasefire|coup|conflict|elections?|nato|treaty|bombing?|airstrike|explosion|assassination|hostage|forces|army|navy|president|prime\s+minister)\b/i,
  crypto:      /\b(bitcoin|ethereum|crypto(currency)?|blockchain|defi|nft|tokens?|binance|coinbase|altcoin|stablecoin|solana|ripple|xrp|dogecoin|web3)\b/i,
  economia:    /\b(fed|federal\s+reserve|interest\s+rate|rate\s+(cut|hike)|inflation|gdp|jobs\s+report|tariffs?|trade\s+(deal|war)|recession|imf|treasury|deficit|unemployment|dow\s+jones|s&p|nasdaq|stock\s+market)\b/i,
  esportes:    /\b(nba|nfl|world\s+cup|championship|olympics|super\s*bowl|fifa|formula\s*(1|one)|ufc|wimbledon|euro\s*(cup)?|tournament)\b/i
};

const matchedCategories = Object.keys(CATEGORIES).filter(cat => CATEGORIES[cat].test(originalText));

if (matchedCategories.length > 0) {
  const hasActiveCategory = matchedCategories.some(cat => userFilters[cat] !== false);
  if (!hasActiveCategory) {
    return [{ json: { ...data, ai_prompt: "NO_TRADE", pre_no_trade: true,
      pre_no_trade_reason: `Category disabled by user filters: ${matchedCategories.join(', ')}`,
      credibility_score: credibilityScore, author_verified: isVerified } }];
  }
}

// Pre-filter: YouTube links from low-credibility accounts are not primary news sources
const hasYouTubeRef = /via @YouTube|youtube\.com|youtu\.be/i.test(originalText);
const isLowCredibility = followers < 5000;

if (hasYouTubeRef && isLowCredibility) {
  return [{ json: { ...data, ai_prompt: "NO_TRADE", pre_no_trade: true, pre_no_trade_reason: "YouTube link from low-follower account (< 5000 followers)", credibility_score: credibilityScore, author_verified: isVerified } }];
}

const prompt = `You are a Polymarket prediction market expert. Analyze this tweet and determine if it contains breaking news that would affect prediction markets.

Tweet: "${tweetText}"
Author: @${author} (${followers} followers)

TASK: If this tweet reports a real-world event relevant to prediction markets (elections, policy decisions, geopolitical events, economic announcements, regulatory changes, conflicts, etc.), respond with the best 2-5 word Polymarket search query that will find the most relevant active markets.

RULES for your query:
- Use 2 to 5 words minimum
- Use full English words only — no abbreviations, no ticker symbols, no acronyms
- Never use ALL CAPS words (write 'bitcoin' not 'BTC' or 'BIT', 'federal reserve' not 'FED', 'artificial intelligence' not 'AI')
- Be specific: combine the actor + action or topic + context
- Focus on the event, not the asset price

DISQUALIFY with NO_TRADE if ANY of the following apply:
- The tweet shares or links to a YouTube video (content like "via @YouTube", "youtu.be", commentary, video titles)
- The tweet is a retweet or quote of a video rather than original reporting
- The author has fewer than 10,000 followers AND the claim is unverified or unattributed
- The tweet text is clearly a video title or clickbait headline without factual detail
- The tweet is a reply, personal opinion, joke, insult, or spam
- The tweet does NOT relate to any verifiable event that prediction markets would track

Examples of GOOD queries: fed rate cut, iran nuclear deal, trump china tariff, ukraine russia ceasefire, bitcoin etf approval, israel iran attack
Examples of BAD queries (never do this): BIT, BTC, FED, AI, Iran, Trump, Bitcoin

Respond with ONLY the search query or NO_TRADE. Nothing else.`;

return [{ json: { ...data, ai_prompt: prompt, credibility_score: credibilityScore, author_verified: isVerified } }];

const item = $input.first();
const response = item.json;
const newsData = $('Preparar Prompt IA').first().json;

// Respect pre-filter from n13 — skip LLM response if already disqualified
if (newsData.pre_no_trade) {
  return [{ json: { signal: "NO_TRADE", reason: newsData.pre_no_trade_reason || "Pre-filtered: low-credibility source" } }];
}

let aiQuery = (response.text || response.response || response.output || "").trim();
aiQuery = aiQuery.replace(/[\"']/g, "").replace(/\s+/g, " ").trim();

if (!aiQuery || aiQuery.toUpperCase().startsWith("NO_") || aiQuery.toUpperCase() === "NO") {
  return [{ json: { signal: "NO_TRADE", reason: "LLM determinou que o tweet nao e relevante para mercados de predicao" } }];
}

return [{
  json: {
    news_text: newsData.news_text,
    tweet_id: newsData.tweet_id,
    tweet_url: newsData.tweet_url,
    author: newsData.author,
    author_followers: newsData.author_followers,
    search_query: aiQuery,
    ai_query: aiQuery,
    timestamp: newsData.timestamp
  }
}];

const newsData = $('Extrair Query IA').first().json;
const responseData = $input.first().json;

// public-search retorna { events: [...], pagination: {...} }
const events = responseData.events || [];

// Extrair todos os mercados dos eventos
let allMarkets = [];
for (const event of events) {
  if (event.archived) continue;
  const eventMarkets = event.markets || [];
  for (const market of eventMarkets) {
    if (market.active === false || market.closed === true || market.archived === true) continue;
    allMarkets.push(Object.assign({}, market, {
      eventSlug: event.slug,
      eventTitle: event.title
    }));
  }
}

// Filtrar por volume > $500
allMarkets = allMarkets.filter(function(m) {
  return parseFloat(m.volumeNum || m.volume || 0) > 500;
});

if (allMarkets.length === 0) {
  return [{ json: {
    signal: 'NO_TRADE',
    reason: 'Nenhum mercado ativo encontrado para: ' + (newsData.ai_query || newsData.search_query || ''),
    news_text: newsData.news_text,
    tweet_id: newsData.tweet_id,
    author: newsData.author,
    author_followers: newsData.author_followers,
    ai_query: newsData.ai_query
  } }];
}

const queryWords = (newsData.ai_query || '').toLowerCase().split(/\s+/).filter(function(w) { return w.length > 2; });
const threshold = queryWords.length >= 3 ? 2 : 1;

const filtered = allMarkets
  .filter(function(m) {
    if (queryWords.length === 0) return true;
    const text = [
      m.question || '',
      (m.description || '').substring(0, 300),
      m.eventTitle || '',
      m.groupItemTitle || ''
    ].join(' ').toLowerCase();
    const matchCount = queryWords.filter(function(word) { return text.includes(word); }).length;
    return matchCount >= threshold;
  })
  .sort(function(a, b) {
    return parseFloat(b.volumeNum || b.volume || 0) - parseFloat(a.volumeNum || a.volume || 0);
  })
  .slice(0, 5);

if (filtered.length === 0) {
  return [{ json: {
    signal: 'NO_TRADE',
    reason: 'Nenhum mercado passou no filtro de relevancia para: ' + (newsData.ai_query || ''),
    news_text: newsData.news_text,
    tweet_id: newsData.tweet_id,
    author: newsData.author,
    author_followers: newsData.author_followers,
    ai_query: newsData.ai_query
  } }];
}

return [{ json: {
  markets: filtered,
  market_count: filtered.length,
  news_text: newsData.news_text,
  tweet_id: newsData.tweet_id,
  tweet_url: newsData.tweet_url,
  author: newsData.author,
  author_followers: newsData.author_followers,
  ai_query: newsData.ai_query,
  timestamp: newsData.timestamp
} }];

const item = $input.first();
const data = item.json;

if (data.signal === "NO_TRADE") { return [item]; }

const markets = data.markets || [];
if (markets.length === 0) {
  return [{ json: { signal: "NO_TRADE", reason: "Lista de mercados vazia" } }];
}

const top = markets[0];
const news = data.news_text || "";

function esc(text) {
  return (text || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

let yesPrice = 0.5;
try {
  const prices = typeof top.outcomePrices === "string"
    ? JSON.parse(top.outcomePrices)
    : (top.outcomePrices || []);
  yesPrice = parseFloat(prices[0] || 0.5);
} catch(e) {}

const volume = parseFloat(top.volumeNum || top.volume || 0);
const yesPct = Math.round(yesPrice * 100);

const sentiment = data.sentiment || "POSITIVE";
let direction, expectedTo, confidence;
if (sentiment === "NEGATIVE") {
  direction = "BUY_NO";
  expectedTo = Math.max(yesPct - (yesPrice >= 0.70 ? 20 : 12), 5);
  confidence = yesPrice >= 0.70 ? 68 : 60;
} else {
  direction = "BUY_YES";
  expectedTo = Math.min(yesPct + (yesPrice <= 0.30 ? 20 : 12), 95);
  confidence = yesPrice <= 0.30 ? 70 : 60;
}

if (volume > 100000) confidence = Math.min(confidence + 8, 88);
if (volume > 500000) confidence = Math.min(confidence + 5, 88);

const followers = data.author_followers || 0;
if (followers > 100000) confidence = Math.min(confidence + 5, 88);

const eventSlug = top.eventSlug || (top.events && top.events[0] && top.events[0].slug) || "";
const marketSlug = top.slug || "";
let marketUrl;
if (eventSlug && marketSlug) {
  marketUrl = "https://polymarket.com/event/" + eventSlug + "/" + marketSlug;
} else if (eventSlug) {
  marketUrl = "https://polymarket.com/event/" + eventSlug;
} else if (marketSlug) {
  marketUrl = "https://polymarket.com/event/" + marketSlug;
} else if (top.id) {
  marketUrl = "https://polymarket.com/markets?id=" + top.id;
} else {
  marketUrl = "https://polymarket.com/markets?search=" + encodeURIComponent(data.ai_query || "");
}
const question = esc(top.question || top.title || "N/A");
const newsSummary = esc(news.length > 120 ? news.substring(0, 120) + "..." : news);
const authorInfo = data.author ? "@" + esc(data.author) : "fonte desconhecida";
const aiQueryInfo = data.ai_query ? "\n\uD83E\uDD16 <b>Query IA:</b> <code>" + esc(data.ai_query) + "</code>" : "";

const msg = "🚨 <b>ALERTA DE TRADE - POLYMARKET</b>\n\n"
  + "🐦 <b>Tweet de " + authorInfo + ":</b>\n" + newsSummary + "\n\n"
  + "📊 <b>Mercado:</b>\n" + question + "\n\n"
  + "🎯 <b>Direcao:</b> <code>" + direction + "</code>\n"
  + "💪 <b>Confianca:</b> " + confidence + "%\n"
  + "📈 <b>Movimento:</b> " + yesPct + "% \u2192 " + expectedTo + "%\n"
  + "💰 <b>Volume:</b> $" + Math.round(volume).toLocaleString("en-US") + aiQueryInfo + "\n\n"
  + "🐦 " + (data.tweet_url || "") + "\n"
  + "🔗 " + marketUrl;

return [{ json: {
  signal: "TRADE",
  market_id: top.id || "",
  market_question: question,
  market_url: marketUrl,
  direction: direction,
  confidence: confidence,
  expected_from: yesPct,
  expected_to: expectedTo,
  current_price_yes: yesPct,
  volume: volume,
  news_summary: newsSummary,
  tweet_id: data.tweet_id || "",
  tweet_url: data.tweet_url || "",
  author: data.author || "",
  author_followers: data.author_followers || 0,
  ai_query: data.ai_query || "",
  telegram_message: msg,
  timestamp: new Date().toISOString()
} }];

const item = $input.first();
const d = item.json;

// Se já é NO_TRADE ou sem mercados, marcar skip — não chamar o LLM
if (d.signal === 'NO_TRADE' || !d.markets || d.markets.length === 0) {
  return [{ json: { ...d, skip_validation: true, ai_validation_prompt: 'YES' } }];
}

function sanitize(text) {
  return (text || '')
    .replace(/https?:\/\/\S+/g, '')
    .replace(/\*/g, '')
    .replace(/[\uD800-\uDFFF]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

const market = d.markets[0];
const news = sanitize(d.news_text).substring(0, 250);

const prompt = `You are validating if a Polymarket prediction market is relevant to a breaking news tweet.

Tweet: "${news}"
Market question: "${market.question}"

Does this market DIRECTLY relate to the news in the tweet? Answer YES if the news could move the market probability. Answer NO if the connection is weak, indirect, or about a different topic.

Answer with only YES or NO.`;

return [{ json: { ...d, skip_validation: false, ai_validation_prompt: prompt } }];

const llmOutput = $input.first().json;
const originalData = $('Filtrar Mercados').first().json;

// Caso skip: NO_TRADE original ou sem mercados — propagar sem validar
if (originalData.signal === 'NO_TRADE' || !originalData.markets || originalData.skip_validation) {
  return [{ json: originalData }];
}

const answer = (llmOutput.response && llmOutput.response.text
  ? llmOutput.response.text
  : llmOutput.text || llmOutput.output || ''
).trim().toUpperCase();

if (!answer.startsWith('YES')) {
  return [{ json: {
    signal: 'NO_TRADE',
    reason: 'Validação LLM: mercado não relevante para esta notícia',
    news_text: originalData.news_text,
    tweet_id: originalData.tweet_id,
    tweet_url: originalData.tweet_url,
    author: originalData.author,
    author_followers: originalData.author_followers,
    ai_query: originalData.ai_query
  } }];
}

return [{ json: originalData }];

const item = $input.first();
const d = item.json;

// Se NO_TRADE ou sem mercados, skip — não chamar o LLM
if (d.signal === 'NO_TRADE' || !d.markets || d.markets.length === 0) {
  return [{ json: { ...d, skip_sentiment: true, ai_sentiment_prompt: 'POSITIVE' } }];
}

function sanitize(text) {
  return (text || '')
    .replace(/https?:\/\/\S+/g, '')
    .replace(/\*/g, '')
    .replace(/[\uD800-\uDFFF]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

const market = d.markets[0];
const news = sanitize(d.news_text).substring(0, 250);

const prompt = `You are a Polymarket prediction market expert.

News tweet: "${news}"
Market question: "${market.question}"

Is this news POSITIVE or NEGATIVE for the YES outcome of this market?
- POSITIVE: the news increases the probability that YES is correct
- NEGATIVE: the news decreases the probability that YES is correct

Answer with only POSITIVE or NEGATIVE.`;

return [{ json: { ...d, skip_sentiment: false, ai_sentiment_prompt: prompt } }];

const llmOutput = $input.first().json;
const originalData = $('Preparar Sentimento IA').first().json;

// Se skip (NO_TRADE ou sem mercados), propagar sem alterar
if (originalData.skip_sentiment || originalData.signal === 'NO_TRADE') {
  return [{ json: originalData }];
}

const answer = (llmOutput.response && llmOutput.response.text
  ? llmOutput.response.text
  : llmOutput.text || llmOutput.output || ''
).trim().toUpperCase();

const sentiment = answer.startsWith('NEGATIVE') ? 'NEGATIVE' : 'POSITIVE';

return [{ json: { ...originalData, sentiment } }];

const item = $input.first();
const message = item.json.message || {};
const text = (message.text || '').trim();
const chatId = message.chat && message.chat.id ? String(message.chat.id) : null;

// Só processa mensagens do chat autorizado
const AUTHORIZED_CHAT_ID = '2074413015';
if (!chatId || chatId !== AUTHORIZED_CHAT_ID) { return []; }

// Só processa comandos (começam com /)
if (!text.startsWith('/')) { return []; }

const staticData = $getWorkflowStaticData('global');
if (!staticData.userFilters) {
  staticData.userFilters = {
    geopolitica: true,
    crypto: true,
    economia: true,
    esportes: true
  };
}

const VALID_CATEGORIES = ['geopolitica', 'crypto', 'economia', 'esportes'];

// Remove acentos para aceitar "geopolítica" e "geopolitica" igualmente
function normalize(s) {
  return (s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

const parts = text.split(/\s+/);
const command = normalize(parts[0]);
const arg = normalize(parts[1] || '');

function statusText() {
  const f = staticData.userFilters;
  return VALID_CATEGORIES.map(c => (f[c] !== false ? '✅' : '❌') + ' ' + c).join('\n');
}

let responseText = '';

if (command === '/filtros' || command === '/categorias') {
  responseText = '<b>Filtros de categoria ativos:</b>\n\n' + statusText() +
    '\n\n<i>Use /ativar ou /desativar &lt;categoria&gt; para alterar.</i>';

} else if (command === '/ativar') {
  if (!arg || !VALID_CATEGORIES.includes(arg)) {
    responseText = '❓ Categoria inválida.\n\nOpções: <code>' + VALID_CATEGORIES.join(', ') + '</code>';
  } else {
    staticData.userFilters[arg] = true;
    responseText = '✅ Categoria <b>' + arg + '</b> ativada.\n\n' + statusText();
  }

} else if (command === '/desativar') {
  if (!arg || !VALID_CATEGORIES.includes(arg)) {
    responseText = '❓ Categoria inválida.\n\nOpções: <code>' + VALID_CATEGORIES.join(', ') + '</code>';
  } else {
    const activeCount = VALID_CATEGORIES.filter(c => staticData.userFilters[c] !== false).length;
    if (activeCount <= 1 && staticData.userFilters[arg] !== false) {
      responseText = '⚠️ Você precisa manter ao menos uma categoria ativa.';
    } else {
      staticData.userFilters[arg] = false;
      responseText = '❌ Categoria <b>' + arg + '</b> desativada.\n\n' + statusText();
    }
  }

} else if (command === '/help' || command === '/start') {
  responseText = '<b>Comandos de configuração:</b>\n\n'
    + '/filtros — ver categorias ativas\n'
    + '/ativar &lt;categoria&gt; — ativar categoria\n'
    + '/desativar &lt;categoria&gt; — desativar categoria\n\n'
    + '<b>Categorias disponíveis:</b>\n'
    + '• <code>geopolitica</code> — guerras, eleições, diplomacia\n'
    + '• <code>crypto</code> — Bitcoin, Ethereum, DeFi\n'
    + '• <code>economia</code> — Fed, inflação, tarifas, PIB\n'
    + '• <code>esportes</code> — Copa do Mundo, NBA, NFL';

} else {
  // Comando não reconhecido — ignora silenciosamente
  return [];
}

return [{ json: { chat_id: chatId, response_text: responseText } }];
